// markdown-mini — a small CommonMark subset renderer.
//
// Two-pass parser: first pass identifies block-level structures
// (headings, paragraphs, code blocks, lists, blockquotes); second
// pass renders inline content (emphasis, code, links, escapes)
// within paragraphs and heading text.
//
// Spec subset:
//   # H1, ## H2, ..., ###### H6 (ATX headings)
//   `inline code`
//   *italic* and **bold**
//   [link text](url)
//   ```fenced code blocks```
//   indented (4-space) code blocks
//   > blockquote
//   - unordered list items
//   blank-line paragraph separation
//
// Out of scope: setext headings, link references, tables, images,
// autolinks, HTML pass-through.

const HTML_ESCAPE = { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" };
function escapeHtml(s) {
    return String(s).replace(/[&<>"]/g, (c) => HTML_ESCAPE[c]);
}

// ── Block-level lexer ──────────────────────────────────────────────
// Returns array of {type, ...} blocks.
function blockify(src) {
    const lines = src.replace(/\r\n?/g, "\n").split("\n");
    const blocks = [];
    let i = 0;
    while (i < lines.length) {
        const line = lines[i];
        // Blank line.
        if (/^\s*$/.test(line)) { i++; continue; }
        // Fenced code block.
        const fenceMatch = /^```(.*)$/.exec(line);
        if (fenceMatch) {
            const lang = fenceMatch[1].trim();
            const codeLines = [];
            i++;
            while (i < lines.length && !/^```\s*$/.test(lines[i])) {
                codeLines.push(lines[i]);
                i++;
            }
            i++; // consume closing fence (if present)
            blocks.push({ type: "code_block", lang, text: codeLines.join("\n") });
            continue;
        }
        // ATX heading.
        const headingMatch = /^(#{1,6})\s+(.*?)\s*#*\s*$/.exec(line);
        if (headingMatch) {
            blocks.push({ type: "heading", level: headingMatch[1].length, text: headingMatch[2] });
            i++;
            continue;
        }
        // Indented (4-space) code block.
        if (/^    /.test(line)) {
            const codeLines = [];
            while (i < lines.length && (/^    /.test(lines[i]) || /^\s*$/.test(lines[i]))) {
                if (/^\s*$/.test(lines[i])) {
                    // include a blank line only if more indented code follows
                    let j = i + 1;
                    while (j < lines.length && /^\s*$/.test(lines[j])) j++;
                    if (j < lines.length && /^    /.test(lines[j])) {
                        codeLines.push("");
                        i = j;
                        continue;
                    }
                    break;
                }
                codeLines.push(lines[i].slice(4));
                i++;
            }
            blocks.push({ type: "code_block", lang: "", text: codeLines.join("\n") });
            continue;
        }
        // Blockquote.
        if (/^>\s?/.test(line)) {
            const quoteLines = [];
            while (i < lines.length && /^>\s?/.test(lines[i])) {
                quoteLines.push(lines[i].replace(/^>\s?/, ""));
                i++;
            }
            blocks.push({ type: "blockquote", children: blockify(quoteLines.join("\n")) });
            continue;
        }
        // Unordered list.
        if (/^[-*+]\s+/.test(line)) {
            const items = [];
            while (i < lines.length && /^[-*+]\s+/.test(lines[i])) {
                items.push(lines[i].replace(/^[-*+]\s+/, ""));
                i++;
            }
            blocks.push({ type: "list", items });
            continue;
        }
        // Paragraph: until blank line or block-level marker.
        const para = [line];
        i++;
        while (i < lines.length && !/^\s*$/.test(lines[i]) &&
               !/^#{1,6}\s+/.test(lines[i]) &&
               !/^```/.test(lines[i]) &&
               !/^>\s?/.test(lines[i]) &&
               !/^[-*+]\s+/.test(lines[i]) &&
               !/^    /.test(lines[i])) {
            para.push(lines[i]);
            i++;
        }
        blocks.push({ type: "paragraph", text: para.join(" ") });
    }
    return blocks;
}

// ── Inline renderer ────────────────────────────────────────────────
// Order matters: escape first to a sentinel form, then expand inline
// constructs in priority order (code > links > bold > italic), then
// substitute the escapes back. Avoids re-processing escaped text as
// markdown.
function inline(text) {
    // Step 1: capture backslash-escapes and inline code spans BEFORE
    // any HTML escaping (so we know what the literal source chars
    // are). Sentinel-substitute them out.
    const ESCAPES = [];
    text = text.replace(/\\([\\`*_\[\]()<>#])/g, (_, ch) => {
        ESCAPES.push(ch);
        return `\x00${ESCAPES.length - 1}\x00`;
    });
    const CODES = [];
    text = text.replace(/`([^`]+)`/g, (_, code) => {
        CODES.push(code);
        return `\x01${CODES.length - 1}\x01`;
    });
    // Step 2: HTML-escape ALL remaining user text. Markdown inline syntax
    // ([](), **, *) uses ASCII chars that escapeHtml leaves alone, so the
    // subsequent transforms still work on escaped text. Critically this
    // prevents raw HTML pass-through (security).
    text = escapeHtml(text);
    // Step 3: apply inline markdown transforms on the escaped text.
    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g,
        (_, t, u) => `<a href="${u}">${t}</a>`);
    text = text.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
    text = text.replace(/\*([^*]+)\*/g, "<em>$1</em>");
    // Step 4: substitute back. Backslash-escaped chars are emitted as
    // their literal but HTML-escaped form; code-span content is HTML-
    // escaped and wrapped in <code>.
    text = text.replace(/\x00(\d+)\x00/g, (_, n) => escapeHtml(ESCAPES[+n]));
    text = text.replace(/\x01(\d+)\x01/g, (_, n) => `<code>${escapeHtml(CODES[+n])}</code>`);
    return text;
}

// ── Renderer ───────────────────────────────────────────────────────
function renderBlocks(blocks) {
    const parts = [];
    for (const b of blocks) {
        switch (b.type) {
            case "heading":
                parts.push(`<h${b.level}>${inline(b.text)}</h${b.level}>`);
                break;
            case "paragraph":
                parts.push(`<p>${inline(b.text)}</p>`);
                break;
            case "code_block": {
                const cls = b.lang ? ` class="language-${escapeHtml(b.lang)}"` : "";
                parts.push(`<pre><code${cls}>${escapeHtml(b.text)}</code></pre>`);
                break;
            }
            case "blockquote":
                parts.push(`<blockquote>${renderBlocks(b.children)}</blockquote>`);
                break;
            case "list":
                parts.push("<ul>" + b.items.map(i => `<li>${inline(i)}</li>`).join("") + "</ul>");
                break;
        }
    }
    return parts.join("");
}

export function render(src) {
    return renderBlocks(blockify(src));
}

export default { render };
